## Add up to `max_add` new abscissae, keeping a minimum spacing so that the
## tangent-intersection points remain well-conditioned.
insert_abscissae <- function(xs, cand, max_add, max_total, min_gap = 1e-3) {
  if (length(cand) == 0L) return(xs)
  cand <- sort(unique(cand))
  spread <- diff(range(xs))
  if (is.finite(spread) && spread > 0) min_gap <- max(min_gap, 1e-3 * spread)
  added <- numeric(0)
  for (c in cand) {
    if (length(xs) + length(added) >= max_total) break
    if (length(added) >= max_add) break
    allpts <- c(xs, added)
    if (min(abs(allpts - c)) > min_gap) added <- c(added, c)
  }
  sort(unique(c(xs, added)))
}

